// Parse individual research output
const rawOutput = $json;
const taskContext = $input.all()[0].json;
let research = {};

try {
  let text = rawOutput.output || rawOutput;
  if (typeof text === 'string') {
    const jsonMatch = text.match(/```json\s*([\s\S]*?)\s*```/) ||
                     text.match(/```\s*([\s\S]*?)\s*```/) ||
                     [null, text];
    research = JSON.parse((jsonMatch[1] || text).trim());
  } else {
    research = text;
  }
} catch (error) {
  research = {
    queryId: taskContext.query?.queryId || 'unknown',
    sectionTitle: taskContext.query?.sectionItFeeds || 'Research Section',
    sectionContent: typeof rawOutput.output === 'string' ? rawOutput.output : 'Content pending',
    keyStats: [],
    quotableInsight: '',
    examples: [],
    actionableFramework: null,
    linkedInHooks: [],
    sources: [],
    seoKeywords: [],
    wordCount: 0
  };
}

research.queryId = research.queryId || taskContext.query?.queryId || 'unknown';
research.sectionTitle = research.sectionTitle || taskContext.query?.sectionItFeeds || 'Section';
research.sectionContent = research.sectionContent || '';
research.keyStats = Array.isArray(research.keyStats) ? research.keyStats : [];
research.quotableInsight = research.quotableInsight || '';
research.examples = Array.isArray(research.examples) ? research.examples : [];
research.linkedInHooks = Array.isArray(research.linkedInHooks) ? research.linkedInHooks : [];
research.sources = Array.isArray(research.sources) ? research.sources : [];
research.seoKeywords = Array.isArray(research.seoKeywords) ? research.seoKeywords : [];
research.wordCount = (research.sectionContent || '').split(/\s+/).length;
research.processedAt = new Date().toISOString();
research.refinedTopic = taskContext.refinedTopic;
research.briefId = taskContext.briefId;
research.proposedTitle = taskContext.proposedTitle;
research.targetReader = taskContext.targetReader;
research.articleAngle = taskContext.articleAngle;
research.authorName = taskContext.authorName;
research.formattedDate = taskContext.formattedDate;
research.formattedDateTime = taskContext.formattedDateTime;

return { json: research };

// Compile all research into structured content
const allItems = $input.all();
const results = allItems.map(item => item.json);

// Sort by queryId
results.sort((a, b) => {
  const aNum = parseInt((a.queryId || '0').replace(/\D/g, '')) || 0;
  const bNum = parseInt((b.queryId || '0').replace(/\D/g, '')) || 0;
  return aNum - bNum;
});

// Build Table of Contents
const toc = results.map((r, i) => `${i + 1}. ${r.sectionTitle}`);

// Compile sections
const sections = results.map(r => ({
  queryId: r.queryId,
  title: r.sectionTitle,
  content: r.sectionContent,
  keyStats: r.keyStats || [],
  quotableInsight: r.quotableInsight || '',
  examples: r.examples || [],
  framework: r.actionableFramework,
  hooks: r.linkedInHooks || [],
  sources: r.sources || [],
  seoKeywords: r.seoKeywords || [],
  wordCount: (r.sectionContent || '').split(/\s+/).length
}));

// Aggregate all data
const allStats = sections.flatMap(s => s.keyStats);
const allHooks = sections.flatMap(s => s.hooks);
const allSources = sections.flatMap(s => s.sources);
const allKeywords = [...new Set(sections.flatMap(s => s.seoKeywords))];
const allQuotes = sections.map(s => s.quotableInsight).filter(q => q);
const totalWords = sections.reduce((sum, s) => sum + s.wordCount, 0);

const refinedTopic = results[0]?.refinedTopic || 'Research Report';
const briefId = results[0]?.briefId || 'N/A';
const proposedTitle = results[0]?.proposedTitle || refinedTopic;
const targetReader = results[0]?.targetReader || 'B2B Leaders';
const articleAngle = results[0]?.articleAngle || 'Comprehensive analysis';
const authorName = results[0]?.authorName || 'YOUR_AUTHOR_NAME';
const formattedDate = results[0]?.formattedDate || new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
const formattedDateTime = results[0]?.formattedDateTime || new Date().toLocaleString('en-US', { month: 'long', day: 'numeric', year: 'numeric', hour: 'numeric', minute: '2-digit', hour12: true });

const compiled = {
  refinedTopic,
  briefId,
  proposedTitle,
  targetReader,
  articleAngle,
  authorName,
  formattedDate,
  formattedDateTime,
  tableOfContents: toc,
  sections,
  allStats,
  allHooks,
  allQuotes,
  allSources,
  allKeywords,
  totalWordCount: totalWords,
  sectionCount: sections.length,
  sourceCount: allSources.length,
  compiledAt: new Date().toISOString(),
  fullResearchContent: sections.map(s => `
## ${s.title}

${s.content}

${s.quotableInsight ? '> ' + s.quotableInsight + '\n\n' : ''}
  `).join('\n---\n\n')
};

return { json: compiled };

