// Clean and prepare article with formatting markers
const editorOutput = $json;
const compiledData = $node['Build TOC and Compile Research'].json;
const queryData = $node['Validate Queries'].json;

let articleText = '';
if (typeof editorOutput.output === 'string') {
  articleText = editorOutput.output;
} else if (typeof editorOutput === 'string') {
  articleText = editorOutput;
} else {
  articleText = JSON.stringify(editorOutput, null, 2);
}

// Remove AI thinking text - find first real content line
const lines = articleText.split('\n');
let startIndex = 0;
for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim().toLowerCase();
  if (line.includes('the user wants') || 
      line.includes('let me analyze') ||
      line.includes('looking at') ||
      line.includes('i need to') ||
      line.includes('i\'ll create')) {
    continue;
  }
  if (lines[i].trim().length > 20 && !line.startsWith('by ') && !line.includes('author')) {
    startIndex = i;
    break;
  }
}

articleText = lines.slice(startIndex).join('\n');

// Clean up markdown and fix dates
articleText = articleText
  .replace(/```[a-z]*\s*/g, '')
  .replace(/#{1,6}\s+/g, '')
  .replace(/\*\*([^*]+)\*\*/g, '{BOLD}$1{/BOLD}')
  .replace(/February 2026/gi, compiledData.formattedDate)
  .replace(/January 2025/gi, compiledData.formattedDate)
  .replace(/\x00/g, '')
  .replace(/[\u2018\u2019]/g, "'")
  .replace(/[\u201C\u201D]/g, '"')
  .trim();

const docTitle = queryData.proposedTitle || `Lead Magnet: ${compiledData.refinedTopic}`;

return {
  json: {
    documentTitle: docTitle,
    articleContent: articleText,
    refinedTopic: compiledData.refinedTopic,
    proposedTitle: queryData.proposedTitle || docTitle,
    proposedSubtitle: queryData.proposedSubtitle || '',
    articleAngle: queryData.articleAngle || '',
    targetReader: compiledData.targetReader || 'B2B Leaders',
    authorName: compiledData.authorName || 'YOUR_AUTHOR_NAME',
    formattedDate: compiledData.formattedDate,
    briefId: compiledData.briefId,
    totalWordCount: compiledData.totalWordCount,
    sectionCount: compiledData.sectionCount,
    sourceCount: compiledData.sourceCount,
    seoKeywords: compiledData.allKeywords || [],
    linkedInHooks: compiledData.allHooks || [],
    quotableInsights: compiledData.allQuotes || [],
    generatedAt: new Date().toISOString()
  }
};

const createResponse = $json;
const documentId = createResponse.documentId;
const documentUrl = `https://docs.google.com/document/d/${documentId}/edit`;

if (!documentId) {
  throw new Error('Failed to create Google Doc');
}

return {
  json: {
    documentId: documentId,
    documentUrl: documentUrl
  }
};

// Build Google Docs API formatting requests
const docData = $('Prepare Document Content').item.json;
const articleText = docData.articleContent;

// Parse text and build formatting requests
const requests = [];
let currentIndex = 1;
const lines = articleText.split('\n');
let fullText = '';
const formatRanges = [];

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];

  // Track bold text
  const boldMatches = [...line.matchAll(/\{BOLD\}(.*?)\{\/BOLD\}/g)];
  for (const match of boldMatches) {
    const cleanedLine = line.replace(/\{BOLD\}|\{\/BOLD\}/g, '');
    const textBefore = cleanedLine.substring(0, cleanedLine.indexOf(match[1]));
    const startIdx = currentIndex + fullText.length + textBefore.length;
    formatRanges.push({
      type: 'bold',
      start: startIdx,
      end: startIdx + match[1].length
    });
  }

  // Track H3 headings
  const h3Match = line.match(/\{H3\}(.*?)\{\/H3\}/);
  if (h3Match) {
    const cleanedLine = line.replace(/\{H3\}|\{\/H3\}/g, '');
    formatRanges.push({
      type: 'heading3',
      start: currentIndex + fullText.length,
      end: currentIndex + fullText.length + cleanedLine.length
    });
  }

  // Add cleaned text
  const cleanLine = line.replace(/\{BOLD\}|\{\/BOLD\}|\{H3\}|\{\/H3\}/g, '');
  fullText += cleanLine + '\n';
}

// Insert text first
requests.push({
  insertText: {
    location: { index: 1 },
    text: fullText
  }
});

// Then apply formatting (in reverse order to maintain indices)
formatRanges.reverse().forEach(range => {
  if (range.type === 'bold') {
    requests.push({
      updateTextStyle: {
        range: {
          startIndex: range.start,
          endIndex: range.end
        },
        textStyle: {
          bold: true
        },
        fields: 'bold'
      }
    });
  } else if (range.type === 'heading3') {
    requests.push({
      updateParagraphStyle: {
        range: {
          startIndex: range.start,
          endIndex: range.end
        },
        paragraphStyle: {
          namedStyleType: 'HEADING_3'
        },
        fields: 'namedStyleType'
      }
    });
  }
});

return {
  json: {
    documentId: $json.documentId,
    requests: requests
  }
};

const docId = $('Extract Doc ID').item.json.documentId;
const docData = $('Prepare Document Content').item.json;

const editUrl = `https://docs.google.com/document/d/${docId}/edit?usp=sharing`;
const viewUrl = `https://docs.google.com/document/d/${docId}/preview`;
const pdfUrl = `https://docs.google.com/document/d/${docId}/export?format=pdf`;

const linkedInPreview = docData.linkedInHooks && docData.linkedInHooks.length > 0 
  ? docData.linkedInHooks[0] 
  : `Check out my latest research on ${docData.refinedTopic}`;

const wordCount = docData.totalWordCount;
const readTime = Math.ceil(wordCount / 200);

const chatMessage = `Your Lead Magnet is Ready!\n\nTitle: ${docData.proposedTitle}\nAuthor: ${docData.authorName}\nDate: ${docData.formattedDate}\nAngle: ${docData.articleAngle}\nTarget Reader: ${docData.targetReader}\n\nArticle Statistics:\n- Word Count: ${wordCount.toLocaleString()} words\n- Reading Time: ~${readTime} minutes\n- Sections: ${docData.sectionCount} chapters\n- Sources: ${docData.sourceCount} references\n- Brief ID: ${docData.briefId}\n\nAccess Your Document:\n- Edit: ${editUrl}\n- View: ${viewUrl}\n- Download PDF: ${pdfUrl}\n\nTop Quotable Insights:\n${docData.quotableInsights.slice(0, 3).map((q, i) => `${i + 1}. "${q}"`).join('\n')}\n\nSEO Keywords: ${docData.seoKeywords.slice(0, 10).join(' | ')}\n\nLinkedIn Post Hook:\n${linkedInPreview}\n\nNext Steps:\n1. Open the Google Doc and review\n2. Important text is already bold\n3. Headings are already formatted\n4. Add your brand styling (fonts, colors, logo)\n5. Publish to LinkedIn Articles or your blog\n6. Share the PDF as a downloadable lead magnet`;

return {
  json: {
    output: chatMessage,
    status: 'success',
    documentTitle: docData.proposedTitle,
    authorName: docData.authorName,
    publicationDate: docData.formattedDate,
    editUrl: editUrl,
    viewUrl: viewUrl,
    pdfUrl: pdfUrl,
    topic: docData.refinedTopic,
    title: docData.proposedTitle,
    subtitle: docData.proposedSubtitle,
    angle: docData.articleAngle,
    targetReader: docData.targetReader,
    briefId: docData.briefId,
    generatedAt: docData.generatedAt,
    stats: {
      wordCount: wordCount,
      readTime: readTime,
      sections: docData.sectionCount,
      sources: docData.sourceCount,
      seoKeywords: (docData.seoKeywords || []).length
    },
    linkedInPostPreview: linkedInPreview,
    quotableInsights: docData.quotableInsights || [],
    seoKeywords: docData.seoKeywords || []
  }
};
